mapper.select:
SELECT id, session_id, user_id, keyword, filters_json, created_at
FROM search_events
WHERE session_id = #{sessionId}
ORDER BY created_at DESC
LIMIT #{limit}

mapper.delete:
DELETE FROM search_events
WHERE session_id = #{sessionId}
  AND id NOT IN (
    SELECT id FROM (
        SELECT id FROM search_events
        WHERE session_id = #{sessionId}
        ORDER BY created_at DESC
        LIMIT #{keep}
    ) keep_ids
  )
